            phase = 3;
            List_Param* params = DeclParser__parseParamList(self);
            Stmt* body = StmtParser__parseBlock(self->sp);
            List_MethodDecl__add(methods, MethodDecl_new(memberName, params, retType, body, 0, memberAccess));
