void sortStrList(List_string* xs) {
    int64_t n = List_string__length(xs);
    for (int64_t i = 1; (i < n); (++i)) {
        char* key = List_string__get(xs, i);
        int64_t j = (i - 1);
        while (((j >= 0) && strLessP2(key, List_string__get(xs, j)))) {
            List_string__set(xs, (j + 1), List_string__get(xs, j));
            j = (j - 1);
        }
        List_string__set(xs, (j + 1), key);
    }
}

int strLessP2(char* a, char* b) {
    int64_t la = (int64_t)strlen(a);
    int64_t lb = (int64_t)strlen(b);
    int64_t n = la;
    if ((lb < n)) {
        n = lb;
    }
    for (int64_t i = 0; (i < n); (++i)) {
        char xa = a[i];
        char xb = b[i];
        int64_t ca = ((int64_t)(xa));
        int64_t cb = ((int64_t)(xb));
        if ((ca < cb)) {
            return 1;
        }
        if ((ca > cb)) {
            return 0;
        }
    }
    return (la < lb);
}

char* showSortedList(List_string* xs) {
    StringBuilder* sb = StringBuilder_new();
    StringBuilder__appendChar(sb, '[');
    int64_t n = List_string__length(xs);
    for (int64_t i = 0; (i < n); (++i)) {
        if ((i > 0)) {
            StringBuilder__append(sb, ", ");
        }
        StringBuilder__appendChar(sb, '\'');
        StringBuilder__append(sb, List_string__get(xs, i));
        StringBuilder__appendChar(sb, '\'');
    }
    StringBuilder__appendChar(sb, ']');
    return StringBuilder__build(sb);
}

