char* dirname(char* path) {
    int64_t n = (int64_t)strlen(path);
    int64_t last = (-1);
    for (int64_t i = 0; (i < n); (++i)) {
        if ((path[i] == '/')) {
            last = i;
        }
    }
    if ((last < 0)) {
        return "";
    }
    return glang_str_substr(path, 0, last);
}

char* basename(char* path) {
    int64_t n = (int64_t)strlen(path);
    int64_t last = (-1);
    for (int64_t i = 0; (i < n); (++i)) {
        if ((path[i] == '/')) {
            last = i;
        }
    }
    if ((last < 0)) {
        return path;
    }
    return glang_str_substr(path, (last + 1), n);
}

char* joinPath(char* dir, char* rel) {
    if ((strcmp(dir, "") == 0)) {
        return rel;
    }
    int64_t n = (int64_t)strlen(dir);
    if ((dir[(n - 1)] == '/')) {
        return glang_str_concat(dir, rel);
    }
    return glang_str_concat(glang_str_concat(dir, "/"), rel);
}

int startsWithStr(char* s, char* prefix) {
    int64_t pn = (int64_t)strlen(prefix);
    if (((int64_t)strlen(s) < pn)) {
        return 0;
    }
    for (int64_t i = 0; (i < pn); (++i)) {
        if ((s[i] != prefix[i])) {
            return 0;
        }
    }
    return 1;
}

char* normPath(char* path) {
    int absolute = 0;
    if ((((int64_t)strlen(path) > 0) && (path[0] == '/'))) {
        absolute = 1;
    }
    List_string* parts = strings__split(path, '/');
    List_string* stack = List_string_new();
    int64_t n = List_string__length(parts);
    for (int64_t i = 0; (i < n); (++i)) {
        char* seg = List_string__get(parts, i);
        if (((strcmp(seg, "") == 0) || (strcmp(seg, ".") == 0))) {
            continue;
        }
        if ((strcmp(seg, "..") == 0)) {
            int64_t sn = List_string__length(stack);
            if (((sn > 0) && (strcmp(List_string__get(stack, (sn - 1)), "..") != 0))) {
                List_string__removeAt(stack, (sn - 1));
            } else {
                if ((!absolute)) {
                    List_string__add(stack, "..");
                }
            }
            continue;
        }
        List_string__add(stack, seg);
    }
    char* joined = strings__join(stack, "/");
    if (absolute) {
        return glang_str_concat("/", joined);
    }
    if ((strcmp(joined, "") == 0)) {
        return ".";
    }
    return joined;
}

