Program* Loader__load(Loader* self, char* rootPath) {
    Loader__loadFile(self, normPath(rootPath), 0, "", 0, 0);
    return Program_new(List_Decl_new(), self->declarations);
}

void Loader__loadFile(Loader* self, char* abspath, int hasVia, char* viaPath, int64_t viaLine, int64_t viaCol) {
    int already = Loader__listContains(self, self->loaded, abspath);
    if (already) {
        return;
    }
    int onStack = Loader__listContains(self, self->visiting, abspath);
    if (onStack) {
        int64_t line = 0;
        int64_t col = 0;
        if (hasVia) {
            line = viaLine;
            col = viaCol;
        }
        GLANG_THROW(LoadError_new(glang_str_concat("circular import: ", Loader__cycleStr(self, abspath)), line, col), "LoadError");
    }
    List_string__add(self->visiting, abspath);
    char* src = Loader__readSource(self, abspath, hasVia, viaPath, viaLine, viaCol);
    GLexer* lex = GLexer_new(src);
    List_Token* tokens = GLexer__tokenize(lex);
    Parser* parser = Parser_new(tokens);
    Program* program = Parser__parse(parser);
    char* baseDir = dirname(abspath);
    List_Decl* imports = program->imports;
    int64_t ni = List_Decl__length(imports);
    for (int64_t i = 0; (i < ni); (++i)) {
        Decl* impDecl = List_Decl__get(imports, i);
        {
            Decl __match__ = (*impDecl);
            switch (__match__.tag) {
            case Decl__ImportDecl: {
                char* path = __match__.data.as_ImportDecl.path;
                char* target = normPath(Loader__resolveImport(self, path, baseDir));
                Loader__loadFile(self, target, 1, path, 0, 0);
                break;
            }
            default: {
                break;
            }
            }
        }
    }
    List_Decl* decls = program->declarations;
    int64_t nd = List_Decl__length(decls);
    for (int64_t j = 0; (j < nd); (++j)) {
        List_Decl__add(self->declarations, List_Decl__get(decls, j));
    }
    int64_t vn = List_string__length(self->visiting);
    List_string__removeAt(self->visiting, (vn - 1));
    List_string__add(self->loaded, abspath);
}

char* Loader__resolveImport(Loader* self, char* importPath, char* baseDir) {
    if (startsWithStr(importPath, "std/")) {
        char* rest = glang_str_substr(importPath, 4, (int64_t)strlen(importPath));
        return joinPath(self->stdlibDir, rest);
    }
    return joinPath(baseDir, importPath);
}

char* Loader__readSource(Loader* self, char* abspath, int hasVia, char* viaPath, int64_t viaLine, int64_t viaCol) {
    int exists = glang_fileexists(abspath);
    if ((!exists)) {
        if (hasVia) {
            GLANG_THROW(LoadError_new(glang_str_concat(glang_str_concat("cannot find imported file '", viaPath), "'"), viaLine, viaCol), "LoadError");
        }
        GLANG_THROW(LoadError_new(glang_str_concat(glang_str_concat("cannot find source file '", abspath), "'"), 0, 0), "LoadError");
    }
    return glang_readfile(abspath);
}

char* Loader__cycleStr(Loader* self, char* abspath) {
    int64_t start = Loader__listIndexOf(self, self->visiting, abspath);
    if ((start < 0)) {
        start = 0;
    }
    List_string* names = List_string_new();
    int64_t n = List_string__length(self->visiting);
    for (int64_t i = start; (i < n); (++i)) {
        List_string__add(names, basename(List_string__get(self->visiting, i)));
    }
    List_string__add(names, basename(abspath));
    return strings__join(names, " -> ");
}

