char* mangleName(char* s) {
    StringBuilder* sb = StringBuilder_new();
    int64_t n = (int64_t)strlen(s);
    int64_t i = 0;
    while ((i < n)) {
        char c = s[i];
        if ((c == '<')) {
            StringBuilder__appendChar(sb, '_');
        } else {
            if ((c == '>')) {
            } else {
                if ((c == ',')) {
                    StringBuilder__appendChar(sb, '_');
                } else {
                    if ((c == ' ')) {
                    } else {
                        if ((((c == ':') && ((i + 1) < n)) && (s[(i + 1)] == ':'))) {
                            StringBuilder__append(sb, "__");
                            i = (i + 2);
                            continue;
                        } else {
                            if (((((c == '*') || (c == '?')) || (c == '[')) || (c == ']'))) {
                            } else {
                                StringBuilder__appendChar(sb, c);
                            }
                        }
                    }
                }
            }
        }
        i = (i + 1);
    }
    return StringBuilder__build(sb);
}

char* cTypeOf(char* t) {
    if ((strcmp(t, "int") == 0)) {
        return "int64_t";
    }
    if ((strcmp(t, "uint") == 0)) {
        return "uint64_t";
    }
    if ((strcmp(t, "float") == 0)) {
        return "double";
    }
    if ((strcmp(t, "bool") == 0)) {
        return "int";
    }
    if ((strcmp(t, "char") == 0)) {
        return "char";
    }
    if ((strcmp(t, "byte") == 0)) {
        return "uint8_t";
    }
    if ((strcmp(t, "string") == 0)) {
        return "char*";
    }
    if ((strcmp(t, "void") == 0)) {
        return "void";
    }
    if ((strcmp(t, "null") == 0)) {
        return "void*";
    }
    if (glang_startswith(t, "fn(")) {
        return "GlangFn";
    }
    if (glang_endswith(t, "*")) {
        return glang_str_concat(cTypeOf(glang_str_substr(t, 0, ((int64_t)strlen(t) - 1))), "*");
    }
    if (glang_endswith(t, "@")) {
        return glang_str_concat(cTypeOf(glang_str_substr(t, 0, ((int64_t)strlen(t) - 1))), "*");
    }
    if (glang_endswith(t, "?")) {
        return cTypeOf(glang_str_substr(t, 0, ((int64_t)strlen(t) - 1)));
    }
    if (glang_endswith(t, "]")) {
        int64_t lb = strings__indexOf(t, '[');
        if ((lb >= 0)) {
            return cTypeOf(glang_str_substr(t, 0, lb));
        }
    }
    return mangleName(t);
}

char* cTypeDecl(char* t, char* varName) {
    if (glang_endswith(t, "]")) {
        int64_t lb = strings__indexOf(t, '[');
        if ((lb >= 0)) {
            char* base = glang_str_substr(t, 0, lb);
            char* size = glang_str_substr(t, (lb + 1), ((int64_t)strlen(t) - 1));
            return glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat(cTypeOf(base), " "), varName), "["), size), "]");
        }
    }
    return glang_str_concat(glang_str_concat(cTypeOf(t), " "), varName);
}

