char* parseFnType(char* fnType) {
    if (((int64_t)strlen(fnType) < 3)) {
        return "";
    }
    if ((strcmp(glang_str_substr(fnType, 0, 3), "fn(") != 0)) {
        return "";
    }
    int64_t closePos = strings__indexOf(fnType, ')');
    if ((closePos < 0)) {
        return "";
    }
    char* paramsStr = glang_str_substr(fnType, 3, closePos);
    char* retStr = glang_str_substr(fnType, (closePos + 3), (int64_t)strlen(fnType));
    return glang_str_concat(glang_str_concat(paramsStr, "|"), retStr);
}

char* emitGlangFnCall(char* varName, char* fnType, List_string* argStrs) {
    char* parts = parseFnType(fnType);
    char* retStr = "int";
    char* paramsStr = "";
    int64_t pipe = strings__indexOf(parts, '|');
    if ((pipe >= 0)) {
        paramsStr = glang_str_substr(parts, 0, pipe);
        retStr = glang_str_substr(parts, (pipe + 1), (int64_t)strlen(parts));
    }
    StringBuilder* cast = StringBuilder_new();
    StringBuilder__append(cast, glang_str_concat(cTypeOf(retStr), "(*)(void*"));
    if (((int64_t)strlen(paramsStr) > 0)) {
        List_string* ptypes = strings__split(paramsStr, ',');
        for (int64_t i = 0; (i < List_string__length(ptypes)); (++i)) {
            StringBuilder__append(cast, glang_str_concat(", ", cTypeOf(List_string__get(ptypes, i))));
        }
    }
    StringBuilder__append(cast, ")");
    StringBuilder* call = StringBuilder_new();
    StringBuilder__append(call, glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat("((", StringBuilder__build(cast)), ")"), varName), ".fn)("), varName), ".cap"));
    for (int64_t i = 0; (i < List_string__length(argStrs)); (++i)) {
        StringBuilder__append(call, glang_str_concat(", ", List_string__get(argStrs, i)));
    }
    StringBuilder__append(call, ")");
    return StringBuilder__build(call);
}

