char* CEmit__methodOwnerClass(CEmit* self, char* cls, char* method) {
    char* cur = cls;
    while ((strcmp(cur, "") != 0)) {
        List_MethodDecl* ms = CEmit__ownMethodsOf(self, cur);
        for (int64_t i = 0; (i < List_MethodDecl__length(ms)); (++i)) {
            if ((strcmp(List_MethodDecl__get(ms, i)->name, method) == 0)) {
                return cur;
            }
        }
        cur = CEmit__classSuperOf(self, cur);
    }
    return cls;
}

