void CEmit__emitFinallyBlock(CEmit* self, Stmt* f) {
    CEmit__ln(self, "{");
    self->indentLevel = (self->indentLevel + 1);
    CEmit__emitBlock(self, f);
    self->indentLevel = (self->indentLevel - 1);
    CEmit__ln(self, "}");
}

int CEmit__hasPendingFinally(CEmit* self, int forReturn) {
    int64_t i = (List_Stmt__length(self->finallyStack) - 1);
    while ((i >= 0)) {
        Stmt* f = List_Stmt__get(self->finallyStack, i);
        if ((f == NULL)) {
            if ((!forReturn)) {
                return 0;
            }
        } else {
            return 1;
        }
        i = (i - 1);
    }
    return 0;
}

void CEmit__emitPendingFinally(CEmit* self, int forReturn) {
    List_Stmt* saved = List_Stmt_new();
    int stop = 0;
    while (((List_Stmt__length(self->finallyStack) > 0) && (!stop))) {
        int64_t last = (List_Stmt__length(self->finallyStack) - 1);
        Stmt* f = List_Stmt__get(self->finallyStack, last);
        List_Stmt__removeAt(self->finallyStack, last);
        List_Stmt__add(saved, f);
        if ((f == NULL)) {
            if ((!forReturn)) {
                stop = 1;
            }
        } else {
            CEmit__emitFinallyBlock(self, f);
        }
    }
    for (int64_t i = (List_Stmt__length(saved) - 1); (i >= 0); (--i)) {
        List_Stmt__add(self->finallyStack, List_Stmt__get(saved, i));
    }
}

void CEmit__emitTryCatch(CEmit* self, Stmt* body, List_CatchClause* catches, Stmt* finallyBlock) {
    int hasFin = (finallyBlock != NULL);
    if (hasFin) {
        List_Stmt__add(self->finallyStack, finallyBlock);
    }
    CEmit__ln(self, "GLANG_TRY_BEGIN");
    self->indentLevel = (self->indentLevel + 1);
    CEmit__emitBlock(self, body);
    self->indentLevel = (self->indentLevel - 1);
    CEmit__ln(self, "GLANG_TRY_END");
    if (hasFin) {
        List_Stmt__removeAt(self->finallyStack, (List_Stmt__length(self->finallyStack) - 1));
    }
    int64_t nc = List_CatchClause__length(catches);
    for (int64_t i = 0; (i < nc); (++i)) {
        CatchClause* c = List_CatchClause__get(catches, i);
        char* baseType = mangleName(showType(c->catchType));
        char* ptrType = glang_str_concat(baseType, "*");
        if ((i > 0)) {
            CEmit__ln(self, "else");
        }
        CEmit__ln(self, glang_str_concat(glang_str_concat("if (glang_instanceof(__exc_frame__.class_name, \"", baseType), "\", __glang_hier__, __glang_hier_len__)) {"));
        self->indentLevel = (self->indentLevel + 1);
        CEmit__ln(self, glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat(ptrType, " "), c->varName), " = ("), ptrType), ")__exc_frame__.obj;"));
        CEmit__pushScope(self);
        CEmit__define(self, c->varName, glang_str_concat(baseType, "*"));
        if (hasFin) {
            List_Stmt__add(self->finallyStack, finallyBlock);
        }
        CEmit__emitBlockInner(self, c->body);
        if (hasFin) {
            List_Stmt__removeAt(self->finallyStack, (List_Stmt__length(self->finallyStack) - 1));
        }
        CEmit__popScope(self);
        self->indentLevel = (self->indentLevel - 1);
        CEmit__ln(self, "}");
    }
    char* reThrow = "GLANG_THROW(__exc_frame__.obj, __exc_frame__.class_name);";
    if ((nc == 0)) {
        if (hasFin) {
            CEmit__emitFinallyBlock(self, finallyBlock);
        }
        CEmit__ln(self, reThrow);
    } else {
        if (hasFin) {
            CEmit__ln(self, "else {");
            self->indentLevel = (self->indentLevel + 1);
            CEmit__emitFinallyBlock(self, finallyBlock);
            CEmit__ln(self, reThrow);
            self->indentLevel = (self->indentLevel - 1);
            CEmit__ln(self, "}");
        } else {
            CEmit__ln(self, glang_str_concat(glang_str_concat("else { ", reThrow), " }"));
        }
    }
    CEmit__ln(self, "GLANG_CATCH_DONE");
    if (hasFin) {
        CEmit__emitFinallyBlock(self, finallyBlock);
    }
}

void CEmit__emitMatch(CEmit* self, Expr* scrutinee, List_MatchArm* arms) {
    char* st = CEmit__infer(self, scrutinee);
    if (glang_endswith(st, "*")) {
        st = glang_str_substr(st, 0, ((int64_t)strlen(st) - 1));
    }
    char* scrutType = mangleName(st);
    CEmit__ln(self, "{");
    self->indentLevel = (self->indentLevel + 1);
    CEmit__ln(self, glang_str_concat(glang_str_concat(glang_str_concat(scrutType, " __match__ = "), CEmit__emitExpr(self, scrutinee)), ";"));
    CEmit__ln(self, "switch (__match__.tag) {");
    int64_t na = List_MatchArm__length(arms);
    for (int64_t i = 0; (i < na); (++i)) {
        MatchArm* arm = List_MatchArm__get(arms, i);
        Pattern* pat = arm->pattern;
        {
            Pattern __match__ = (*pat);
            switch (__match__.tag) {
            case Pattern__WildcardPattern: {
                CEmit__ln(self, "default: {");
                self->indentLevel = (self->indentLevel + 1);
                CEmit__emitBlock(self, arm->body);
                CEmit__ln(self, "break;");
                self->indentLevel = (self->indentLevel - 1);
                CEmit__ln(self, "}");
                break;
            }
            case Pattern__VariantPattern: {
                char* un = __match__.data.as_VariantPattern.unionName;
                char* vn = __match__.data.as_VariantPattern.variantName;
                List_string* binds = __match__.data.as_VariantPattern.bindings;
                char* umn = mangleName(un);
                CEmit__ln(self, glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat("case ", umn), "__"), vn), ": {"));
                self->indentLevel = (self->indentLevel + 1);
                CEmit__pushScope(self);
                List_FieldDecl* vf = CEmit__unionVariantFields(self, un, vn);
                int64_t nb = List_string__length(binds);
                for (int64_t j = 0; (j < nb); (++j)) {
                    char* bname = List_string__get(binds, j);
                    FieldDecl* f = List_FieldDecl__get(vf, j);
                    char* fty = showType(f->fieldType);
                    char* boundType = fty;
                    if (GlobalEnv__is_class(self->env, fty)) {
                        boundType = glang_str_concat(fty, "*");
                    }
                    CEmit__ln(self, glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat(cTypeDecl(boundType, bname), " = __match__.data.as_"), vn), "."), f->name), ";"));
                    CEmit__define(self, bname, boundType);
                }
                CEmit__emitBlock(self, arm->body);
                CEmit__popScope(self);
                CEmit__ln(self, "break;");
                self->indentLevel = (self->indentLevel - 1);
                CEmit__ln(self, "}");
                break;
            }
            }
        }
    }
    CEmit__ln(self, "}");
    self->indentLevel = (self->indentLevel - 1);
    CEmit__ln(self, "}");
}

