            List_StaticFieldDecl* sf = __match__.data.as_ClassDecl.staticFields;
            List_MethodDecl* methods = __match__.data.as_ClassDecl.methods;
            char* sup = __match__.data.as_ClassDecl.superclass;
            List_string* ifc = __match__.data.as_ClassDecl.interfaces;
            ConstructorDecl* ctor = __match__.data.as_ClassDecl.constructor;
            DestructorDecl* dtor = __match__.data.as_ClassDecl.destructor;
            char* acc = __match__.data.as_ClassDecl.access;
            List_string* tps = __match__.data.as_ClassDecl.typeParams;
            Map_string_TypeNode* bn = __match__.data.as_ClassDecl.bounds;
            int mgd = __match__.data.as_ClassDecl.isManaged;
            char* cn = mangleName(name);
            char* selfp = glang_str_concat(cn, "* self");
            if ((ctor != NULL)) {
                StringBuilder__appendLine(self->protos, glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat(cn, "* "), cn), "_new("), CEmit__buildParamList(self, ctor->params)), ");"));
                StringBuilder__appendLine(self->protos, glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat("void ", cn), "__init("), CEmit__buildParamListWith(self, ctor->params, selfp)), ");"));
            } else {
                StringBuilder__appendLine(self->protos, glang_str_concat(glang_str_concat(glang_str_concat(cn, "* "), cn), "_new(void);"));
                StringBuilder__appendLine(self->protos, glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat("void ", cn), "__init("), cn), "* self);"));
            }
            StringBuilder__appendLine(self->protos, glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat("void ", cn), "_delete("), cn), "* self);"));
            int64_t mn = List_MethodDecl__length(methods);
            for (int64_t i = 0; (i < mn); (++i)) {
                MethodDecl* m = List_MethodDecl__get(methods, i);
                char* mc = glang_str_concat(glang_str_concat(cn, "__"), mangleName(m->name));
                char* pl = "";
                if (m->isStatic) {
                    pl = CEmit__buildParamList(self, m->params);
                } else {
                    pl = CEmit__buildParamListWith(self, m->params, selfp);
                }
                StringBuilder__appendLine(self->protos, glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat(CEmit__cRetTypeOf(self, m->returnType), " "), mc), "("), pl), ");"));
            }
