            TypeNode* target = __match__.data.as_ModifierDecl.target;
            List_MethodDecl* methods = __match__.data.as_ModifierDecl.methods;
            char* rawTarget = showType(target);
            char* tgt = mangleName(rawTarget);
            char* selfParam = glang_str_concat(cTypeOf(rawTarget), " self");
            if (GlobalEnv__is_class(self->env, rawTarget)) {
                selfParam = glang_str_concat(tgt, "* self");
            }
            int64_t mn = List_MethodDecl__length(methods);
            for (int64_t i = 0; (i < mn); (++i)) {
                MethodDecl* m = List_MethodDecl__get(methods, i);
                StringBuilder__appendLine(self->protos, glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat(glang_str_concat(CEmit__cRetTypeOf(self, m->returnType), " "), tgt), "__"), mangleName(m->name)), "("), CEmit__buildParamListWith(self, m->params, selfParam)), ");"));
            }
